count_t = 0
count_d = 0
for b in books:
    bid = b["id"]
    if bid in appends:
        for i, t in enumerate(b.get("thoughts", [])):
            if i in appends[bid]:
                t["example"] += appends[bid][i]
                count_t += 1
    if bid in desc_fixes:
        b["description"] = desc_fixes[bid]
        count_d += 1

with open("/root/books/webapp/books.json", "w", encoding="utf-8") as f:
    json.dump(books, f, ensure_ascii=False, separators=(",",":"))
print("Fixed %s thoughts, %s descriptions" % (count_t, count_d))
